type ErrorFirstCallback<T> = (err: Error | null, result?: T) => void;

function promisify<T>(
  fn: (...args: [...any[], ErrorFirstCallback<T>]) => void
): (...args: any[]) => Promise<T> {
  return function (this: unknown, ...args: any[]): Promise<T> {
    return new Promise<T>((resolve, reject) => {
      fn.call(this, ...args, (err: Error | null, result?: T) => {
        if (err) {
          reject(err);
        } else {
          resolve(result as T);
        }
      });
    });
  };
}

