import * as http from 'http';

interface User {
  id: number;
  name: string;
}

function sendJson(res: http.ServerResponse, status: number, body?: unknown): void {
  res.writeHead(status, { 'Content-Type': 'application/json' });
  res.end(body === undefined ? undefined : JSON.stringify(body));
}

function readBody(req: http.IncomingMessage): Promise<string> {
  return new Promise((resolve, reject) => {
    let data = '';
    req.on('data', (chunk) => (data += chunk));
    req.on('end', () => resolve(data));
    req.on('error', reject);
  });
}

function createUsersRouter(): (req: http.IncomingMessage, res: http.ServerResponse) => void {
  const users: User[] = [];
  let nextId = 1;

  return async (req, res) => {
    const url = new URL(req.url || '', `http://${req.headers.host}`);
    const segments = url.pathname.split('/').filter(Boolean);

    if (segments[0] !== 'users') {
      return sendJson(res, 404, { error: 'Not Found' });
    }

    if (req.method === 'GET' && segments.length === 1) {
      return sendJson(res, 200, users);
    }

    if (req.method === 'GET' && segments.length === 2) {
      const id = Number(segments[1]);
      const user = users.find((u) => u.id === id);
      return user ? sendJson(res, 200, user) : sendJson(res, 404, { error: 'Not Found' });
    }

    if (req.method === 'POST' && segments.length === 1) {
      try {
        const raw = await readBody(req);
        const parsed = JSON.parse(raw);
        if (!parsed || typeof parsed.name !== 'string') {
          return sendJson(res, 400, { error: 'Invalid body' });
        }
        const user: User = { id: nextId++, name: parsed.name };
        users.push(user);
        return sendJson(res, 201, user);
      } catch {
        return sendJson(res, 400, { error: 'Invalid JSON' });
      }
    }

    if (req.method === 'DELETE' && segments.length === 2) {
      const id = Number(segments[1]);
      const index = users.findIndex((u) => u.id === id);
      if (index === -1) return sendJson(res, 404, { error: 'Not Found' });
      users.splice(index, 1);
      res.writeHead(204);
      return res.end();
    }

    return sendJson(res, 404, { error: 'Not Found' });
  };
}

