import * as fs from 'fs';
import * as readline from 'readline';

function countMatchingLines(filePath: string, search: string): Promise<number> {
  return new Promise((resolve, reject) => {
    let count = 0;
    let settled = false;

    const stream = fs.createReadStream(filePath, { encoding: 'utf-8' });
    const rl = readline.createInterface({ input: stream, crlfDelay: Infinity });

    stream.on('error', (err) => {
      if (settled) return;
      settled = true;
      rl.close();
      reject(err);
    });

    rl.on('line', (line) => {
      if (line.includes(search)) {
        count++;
      }
    });

    rl.on('close', () => {
      if (settled) return;
      settled = true;
      resolve(count);
    });
  });
}

