import * as fs from 'fs';
import * as path from 'path';
import * as crypto from 'crypto';

interface UploadProgress {
  bytesUploaded: number;
  totalBytes: number;
  percentage: number;
}

interface UploadResult {
  filename: string;
  size: number;
  hash: string;
  duration: number;
}

class UploadHandler {
  private destinationDir: string;

  constructor(destinationDir: string) {
    this.destinationDir = destinationDir;
    if (!fs.existsSync(destinationDir)) {
      fs.mkdirSync(destinationDir, { recursive: true });
    }
  }

  async upload(
    readStream: NodeJS.ReadableStream,
    filename: string,
    maxSize: number,
    allowedTypes: string[],
    onProgress?: (progress: UploadProgress) => void
  ): Promise<UploadResult> {
    const startTime = Date.now();
    const filepath = path.join(this.destinationDir, filename);
    const writeStream = fs.createWriteStream(filepath);
    const hash = crypto.createHash('sha256');

    let bytesUploaded = 0;
    let totalBytes = 0;

    return new Promise((resolve, reject) => {
      // Handle stream errors
      readStream.on('error', (err) => {
        writeStream.destroy();
        fs.unlink(filepath, () => {});
        reject(err);
      });

      writeStream.on('error', (err) => {
        readStream.destroy();
        fs.unlink(filepath, () => {});
        reject(err);
      });

      // Track data and calculate hash
      readStream.on('data', (chunk: Buffer) => {
        bytesUploaded += chunk.length;

        // Check size limit during upload
        if (bytesUploaded > maxSize) {
          readStream.destroy();
          writeStream.destroy();
          fs.unlink(filepath, () => {});
          reject(new Error(`File size exceeds maximum of ${maxSize} bytes`));
          return;
        }

        hash.update(chunk);

        // Emit progress
        if (totalBytes === 0) {
          totalBytes = bytesUploaded;
        }

        if (onProgress) {
          onProgress({
            bytesUploaded,
            totalBytes: bytesUploaded,
            percentage: totalBytes > 0 ? (bytesUploaded / totalBytes) * 100 : 0
          });
        }
      });

      writeStream.on('finish', () => {
        const stats = fs.statSync(filepath);
        const duration = Date.now() - startTime;
        const fileHash = hash.digest('hex');

        // Validate file type if needed (would require additional metadata)
        resolve({
          filename,
          size: stats.size,
          hash: fileHash,
          duration
        });
      });

      // Pipe stream through write
      readStream.pipe(writeStream);
    });
  }
}

