import { Worker } from 'worker_threads';

interface Task<T> {
  fn: () => Promise<T>;
  resolve: (value: T) => void;
  reject: (reason?: any) => void;
}

class WorkerThreadPool<T = any> {
  private poolSize: number;
  private workers: Worker[] = [];
  private taskQueue: Task<any>[] = [];
  private activeWorkers: Set<Worker> = new Set();
  private terminated: boolean = false;

  constructor(poolSize: number) {
    this.poolSize = poolSize;
    this.initializeWorkers();
  }

  private initializeWorkers(): void {
    for (let i = 0; i < this.poolSize; i++) {
      const worker = new Worker('./worker.js');
      this.workers.push(worker);
    }
  }

  async execute<R>(task: () => Promise<R>): Promise<R> {
    if (this.terminated) {
      throw new Error('Pool has been terminated');
    }

    return new Promise<R>((resolve, reject) => {
      const taskObj: Task<R> = { fn: task, resolve, reject };
      this.taskQueue.push(taskObj);
      this.processTasks();
    });
  }

  private processTasks(): void {
    const availableWorker = this.workers.find(
      (w) => !this.activeWorkers.has(w)
    );

    if (!availableWorker || this.taskQueue.length === 0) {
      return;
    }

    const task = this.taskQueue.shift();
    if (!task) return;

    this.activeWorkers.add(availableWorker);

    task
      .fn()
      .then((result) => {
        task.resolve(result);
      })
      .catch((error) => {
        task.reject(error);
      })
      .finally(() => {
        this.activeWorkers.delete(availableWorker);
        this.processTasks();
      });
  }

  async terminate(): Promise<void> {
    this.terminated = true;

    return Promise.all(
      this.workers.map((worker) => worker.terminate())
    ).then(() => {
      this.workers = [];
      this.activeWorkers.clear();
    });
  }
}

