import { AsyncLocalStorage } from 'async_hooks';
import { Request, Response, NextFunction } from 'express';
import { v4 as uuid } from 'uuid';

interface RequestContext {
  requestId: string;
  userId?: string;
  timestamp: number;
  startTime: number;
  dbQueryCount: number;
}

interface Logger {
  info(message: string, data?: any): void;
  error(message: string, error?: any): void;
  debug(message: string, data?: any): void;
}

class RequestContextManager {
  private asyncLocalStorage = new AsyncLocalStorage<RequestContext>();

  getMiddleware() {
    return (req: Request, res: Response, next: NextFunction) => {
      const context: RequestContext = {
        requestId: uuid(),
        userId: (req as any).user?.id,
        timestamp: Date.now(),
        startTime: process.hrtime.bigint(),
        dbQueryCount: 0,
      };

      this.asyncLocalStorage.run(context, () => {
        res.on('finish', () => {
          const duration = this.getRequestDuration();
          console.log(
            `[${context.requestId}] Request completed in ${duration}ms with ${context.dbQueryCount} DB queries`
          );
        });
        next();
      });
    };
  }

  getCurrentContext(): RequestContext | undefined {
    return this.asyncLocalStorage.getStore();
  }

  setCurrentContext(context: Partial<RequestContext>): void {
    const current = this.getCurrentContext();
    if (current) {
      Object.assign(current, context);
    }
  }

  getLogger(): Logger {
    const self = this;
    return {
      info(message: string, data?: any) {
        const context = self.getCurrentContext();
        console.log(
          JSON.stringify({
            level: 'INFO',
            message,
            requestId: context?.requestId,
            timestamp: new Date().toISOString(),
            data,
          })
        );
      },
      error(message: string, error?: any) {
        const context = self.getCurrentContext();
        console.error(
          JSON.stringify({
            level: 'ERROR',
            message,
            requestId: context?.requestId,
            timestamp: new Date().toISOString(),
            error: error?.message || error,
          })
        );
      },
      debug(message: string, data?: any) {
        const context = self.getCurrentContext();
        console.debug(
          JSON.stringify({
            level: 'DEBUG',
            message,
            requestId: context?.requestId,
            timestamp: new Date().toISOString(),
            data,
          })
        );
      },
    };
  }

  recordDbQuery(): void {
    const context = this.getCurrentContext();
    if (context) {
      context.dbQueryCount++;
    }
  }

  getRequestDuration(): number {
    const context = this.getCurrentContext();
    if (!context) return 0;
    const endTime = process.hrtime.bigint();
    return Number((endTime - context.startTime) / BigInt(1000000));
  }
}
